172→/* ═══════════════════════════════════════════════
173→   Paragraph Comment Layer (pcl-)
174→   ═══════════════════════════════════════════════ */
175→
176→/* Warm paragraph hover — signals commentability (JS .pcl-active only) */
177→.chapter-reader-content .editor-paragraph[data-paragraph-index] {
178→    transition: background-color 0.25s ease;
179→    border-radius: 3px;
180→}
181→
182→.pcl-layer {
183→    position: absolute;
184→    top: 0;
185→    left: 0;
186→    right: 0;
187→    bottom: 0;
188→    pointer-events: none;
189→    z-index: 1;
190→}
191→
192→.pcl-badge-anchor {
193→    position: absolute;
194→    right: -4px;
195→    pointer-events: none;
196→    display: flex;
197→    align-items: flex-start;
198→    padding-top: 3px;
199→    padding-left: 20px;
200→    opacity: 0;
201→    transition: opacity 0.15s ease;
202→}
203→
204→.pcl-badge-anchor.pcl-badge-visible {
205→    opacity: 1;
206→    pointer-events: auto;
207→}
208→
209→.pcl-badge {
210→    display: inline-flex;
211→    align-items: center;
212→    gap: 4px;
213→    padding: 5px 8px;
214→    border: 1px solid var(--bg-glass-border);
215→    border-radius: 20px;
216→    background: var(--bg-glass);
217→    backdrop-filter: blur(16px);
218→    -webkit-backdrop-filter: blur(16px);
219→    color: var(--text-secondary);
220→    cursor: pointer;
221→    font-family: var(--font-ui);
222→    font-size: 0.68rem;
223→    font-weight: 600;
224→    letter-spacing: 0.02em;
225→    white-space: nowrap;
226→    box-shadow: var(--shadow-card-sm);
227→    transition: color 0.2s ease, border-color 0.2s ease,
228→                background-color 0.2s ease, box-shadow 0.2s ease,
229→                transform 0.2s ease;
230→}
231→
232→.pcl-badge:hover {
233→    color: var(--accent-amber);
234→    border-color: var(--accent-amber);
235→    background: var(--bg-selection-active);
236→    box-shadow: 0 0 0 3px var(--bg-selection), var(--shadow-card-sm);
237→    transform: scale(1.06);
238→}
239→
240→.pcl-badge-active {
241→    color: var(--accent-amber);
242→    border-color: rgba(212, 168, 83, 0.3);
243→    background: var(--bg-selection);
244→    box-shadow: 0 0 12px rgba(212, 168, 83, 0.1);
245→}
246→
247→.pcl-badge-active:hover {
248→    border-color: var(--accent-amber);
249→    background: var(--bg-selection-active);
250→    box-shadow: 0 0 0 3px var(--bg-selection-active),
251→                0 0 16px rgba(212, 168, 83, 0.14);
252→}
253→
254→.pcl-badge svg {
255→    flex-shrink: 0;
256→}
257→
258→.pcl-badge-count {
259→    line-height: 1;
260→    min-width: 8px;
261→    text-align: center;
262→}
263→
264→@media (max-width: 768px) {
265→    .pcl-badge {
266→        padding: 4px 6px;
267→        font-size: 0.64rem;
268→    }
269→}
270→
271→/* JS-driven active state — highlight only on explicit hover/click, not scroll */
272→.chapter-reader-content .editor-paragraph[data-paragraph-index].pcl-active {
273→    background-color: var(--bg-selection);
274→}
