277→/* ═══════════════════════════════════════════════
278→   Comment Panel (cp-)
279→   ═══════════════════════════════════════════════ */
280→
281→.cp-backdrop {
282→    position: fixed;
283→    inset: 0;
284→    background: var(--bg-overlay);
285→    backdrop-filter: blur(4px);
286→    -webkit-backdrop-filter: blur(4px);
287→    z-index: 200;
288→}
289→
290→.cp-panel {
291→    display: flex;
292→    flex-direction: column;
293→    background: var(--bg-card);
294→    z-index: 201;
295→    overflow: hidden;
296→    box-shadow: var(--shadow-modal);
