327→/* ── Header ── */
328→.cp-header {
329→    display: flex;
330→    align-items: center;
331→    justify-content: space-between;
332→    padding: 0.85rem 1.15rem;
333→    border-bottom: 1px solid var(--border-card);
334→    flex-shrink: 0;
335→}
336→
337→.cp-header-left {
338→    display: flex;
339→    align-items: center;
