535→    border: 1px solid var(--border-card);
536→    border-radius: 10px;
537→    padding: 0.55rem 0.75rem;
538→    resize: none;
539→    min-height: 1.4rem;
540→    max-height: 80px;
541→    outline: none;
542→    overflow-y: auto;
543→    transition: border-color 0.2s ease;
