  1→import React, { useState, useEffect, useRef, useCallback } from 'react';
  2→import { useNavigate, useParams, useLocation } from 'react-router-dom';
  3→import { useAuth } from '../../../Context/useAuth';
  4→import { useChapter, useChapterCommentCounts } from '../hooks/useStoryData';
  5→import { saveReadingProgress } from '../../../../API/StoryApi';
  6→import { motion, AnimatePresence } from 'framer-motion';
  7→import { BeatLoader } from 'react-spinners';
  8→import ParagraphCommentLayer from './ParagraphCommentLayer';
  9→import CommentPanel from './CommentPanel';
 10→
 11→import { LexicalComposer } from '@lexical/react/LexicalComposer';
 12→import { RichTextPlugin } from '@lexical/react/LexicalRichTextPlugin';
 13→import { ContentEditable } from '@lexical/react/LexicalContentEditable';
 14→import { LexicalErrorBoundary } from '@lexical/react/LexicalErrorBoundary';
 15→import { useLexicalComposerContext } from '@lexical/react/LexicalComposerContext';
 16→import { HeadingNode, QuoteNode } from '@lexical/rich-text';
 17→import ImageNode from '../../HomePage/Editor/nodes/ImageNode';
 18→
 19→import './ChapterReader.css';
 20→
 21→const readerTheme = {
 22→    paragraph: 'editor-paragraph',
 23→    heading: {
 24→        h1: 'editor-heading-h1',
 25→        h2: 'editor-heading-h2',
 26→        h3: 'editor-heading-h3',
 27→    },
 28→    quote: 'editor-quote',
 29→    text: {
 30→        bold: 'editor-text-bold',
 31→        italic: 'editor-text-italic',
 32→        underline: 'editor-text-underline',
 33→    },
 34→};
 35→
 36→const ReaderContent = ({ chapter }) => {
 37→    const [editor] = useLexicalComposerContext();
 38→
 39→    useEffect(() => {
 40→        if (chapter?.content && editor) {
 41→            try {
 42→                const content = typeof chapter.content === 'string'
 43→                    ? chapter.content
 44→                    : JSON.stringify(chapter.content);
 45→                const state = editor.parseEditorState(content);
 46→                editor.setEditorState(state);
 47→            } catch (err) {
 48→                console.error('Failed to load chapter content:', err);
 49→            }
 50→            editor.setEditable(false);
 51→        }
 52→    }, [chapter?.id, editor]);
 53→
 54→    return (
 55→        <RichTextPlugin
 56→            contentEditable={<ContentEditable className="chapter-reader-content" />}
 57→            ErrorBoundary={LexicalErrorBoundary}
 58→        />
 59→    );
 60→};
 61→
 62→const ChapterReader = () => {
 63→    const { storyId, chapterId } = useParams();
 64→    const navigate = useNavigate();
 65→    const location = useLocation();
 66→    const { session } = useAuth();
 67→    const token = session?.access_token;
 68→
 69→    const { data: chapter, isLoading } = useChapter(storyId, chapterId, token);
 70→    const { data: commentCounts } = useChapterCommentCounts(chapterId, token);
 71→    const progressTimerRef = useRef(null);
 72→    const scrollRef = useRef(0);
 73→    const bodyRef = useRef(null);
 74→    const hasRestoredRef = useRef(false);
 75→    const [activeComment, setActiveComment] = useState(null);
 76→
 77→    // Save reading progress debounced on scroll
 78→    const saveProgress = useCallback(() => {
 79→        if (!token || !storyId || !chapterId) return;
 80→        saveReadingProgress(token, storyId, chapterId, scrollRef.current).catch(() => {});
 81→    }, [token, storyId, chapterId]);
 82→
 83→    useEffect(() => {
 84→        const handleScroll = () => {
 85→            const scrollTop = window.scrollY || document.documentElement.scrollTop;
 86→            const docHeight = document.documentElement.scrollHeight - window.innerHeight;
 87→            scrollRef.current = docHeight > 0 ? Math.min(scrollTop / docHeight, 1) : 0;
 88→
 89→            if (progressTimerRef.current) clearTimeout(progressTimerRef.current);
 90→            progressTimerRef.current = setTimeout(saveProgress, 3000);
 91→        };
 92→
 93→        window.addEventListener('scroll', handleScroll, { passive: true });
 94→        return () => {
 95→            window.removeEventListener('scroll', handleScroll);
 96→            if (progressTimerRef.current) clearTimeout(progressTimerRef.current);
 97→            // Save on unmount
 98→            saveProgress();
 99→        };
100→    }, [saveProgress]);
101→
102→    // Restore scroll position when resuming from "Continue Reading"
103→    useEffect(() => {
104→        const savedPosition = location.state?.scrollPosition;
105→        if (!savedPosition || hasRestoredRef.current || isLoading || !chapter) return;
106→        hasRestoredRef.current = true;
107→
108→        const timer = setTimeout(() => {
109→            const docHeight = document.documentElement.scrollHeight - window.innerHeight;
110→            if (docHeight > 0) {
111→                window.scrollTo({ top: docHeight * savedPosition, behavior: 'instant' });
112→            }
113→            navigate(location.pathname, { replace: true, state: {} });
114→        }, 150);
115→
116→        return () => clearTimeout(timer);
117→    }, [isLoading, chapter]);
118→
119→    // Reset comment panel when chapter changes
120→    useEffect(() => {
121→        setActiveComment(null);
122→    }, [chapterId]);
123→
124→    // Scroll progress bar
125→    useEffect(() => {
126→        const bar = document.getElementById('chapter-progress-bar');
127→        if (!bar) return;
128→
129→        const updateBar = () => {
130→            const scrollTop = window.scrollY || document.documentElement.scrollTop;
131→            const docHeight = document.documentElement.scrollHeight - window.innerHeight;
132→            const pct = docHeight > 0 ? (scrollTop / docHeight) * 100 : 0;
133→            bar.style.width = `${Math.min(pct, 100)}%`;
134→        };
135→
136→        window.addEventListener('scroll', updateBar, { passive: true });
137→        return () => window.removeEventListener('scroll', updateBar);
138→    }, []);
139→
140→    const editorConfig = {
141→        namespace: 'ChapterReader',
142→        theme: readerTheme,
143→        nodes: [ImageNode, HeadingNode, QuoteNode],
144→        editable: false,
145→        onError(error) { console.error('Lexical error:', error); },
146→    };
147→
148→    if (isLoading) {
149→        return (
150→            <div className="chapter-reader">
151→                <div className="chapter-reader-loading">
152→                    <BeatLoader size={10} color="var(--text-muted)" />
153→                </div>
154→            </div>
155→        );
156→    }
157→
158→    if (!chapter) {
159→        return (
160→            <div className="chapter-reader">
