162→            </div>
163→        );
164→    }
165→
166→    const prevCh = chapter.prev_chapter;
167→    const nextCh = chapter.next_chapter;
168→
169→    return (
170→        <motion.div
171→            className="chapter-reader"
172→            initial={{ opacity: 0 }}
173→            animate={{ opacity: 1 }}
174→            transition={{ duration: 0.2 }}
175→        >
176→            {/* Progress bar */}
177→            <div className="chapter-progress-track">
178→                <div id="chapter-progress-bar" className="chapter-progress-fill" />
179→            </div>
180→
181→            {/* Header */}
182→            <div className="chapter-reader-header">
