184→                    className="chapter-reader-back"
185→                    onClick={() => navigate(`/home/stories/${storyId}`)}
186→                >
187→                    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="var(--text-secondary)">
188→                        <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
189→                    </svg>
190→                </button>
191→                <div className="chapter-reader-header-info">
192→                    <span className="chapter-reader-chapter-label">Chapter {chapter.chapter_number}</span>
