194→                </div>
195→            </div>
196→
197→            {/* Content */}
198→            <div className="chapter-reader-body" ref={bodyRef}>
199→                <LexicalComposer initialConfig={editorConfig}>
200→                    <ReaderContent chapter={chapter} />
201→                </LexicalComposer>
202→                <ParagraphCommentLayer
203→                    containerRef={bodyRef}
204→                    commentCounts={commentCounts}
205→                    onParagraphClick={setActiveComment}
