207→            </div>
208→
209→            {/* Comment Panel */}
210→            <AnimatePresence>
211→                {activeComment && (
212→                    <CommentPanel
213→                        chapterId={chapterId}
214→                        activeComment={activeComment}
215→                        onClose={() => setActiveComment(null)}
216→                    />
217→                )}
218→            </AnimatePresence>
219→
220→            {/* Navigation */}
221→            <div className="chapter-reader-nav">
222→                {prevCh ? (
223→                    <button
224→                        className="chapter-nav-btn chapter-nav-prev"
225→                        onClick={() => navigate(`/home/stories/${storyId}/chapter/${prevCh.id}`)}
226→                    >
227→                        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
228→                            <path d="M15.41 7.41L14 6l-6 6 6 6 1.41-1.41L10.83 12z"/>
229→                        </svg>
230→                        <span>Ch. {prevCh.chapter_number}: {prevCh.title}</span>
231→                    </button>
232→                ) : <div />}
233→                {nextCh ? (
234→                    <button
235→                        className="chapter-nav-btn chapter-nav-next"
236→                        onClick={() => navigate(`/home/stories/${storyId}/chapter/${nextCh.id}`)}
237→                    >
238→                        <span>Ch. {nextCh.chapter_number}: {nextCh.title}</span>
239→                        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
