107→// ── My Library ──
108→export const getMyLibraryService = async (userId, limit, before) => {
109→    if (!userId) {
110→        throw { status: 400, error: 'userId is required' };
111→    }
112→
113→    const parsedLimit = Math.min(Math.max(parseInt(limit) || 5, 1), 20);
114→
115→    // Get library entries ordered by most recently added
116→    let libQuery = supabase
117→        .from('story_library')
118→        .select('story_id, added_at')
119→        .eq('user_id', userId)
120→        .order('added_at', { ascending: false })
121→        .limit(parsedLimit + 1);
122→
123→    if (before) {
124→        libQuery = libQuery.lt('added_at', before);
125→    }
126→
127→    const { data: libraryEntries, error: libError } = await libQuery;
128→
129→    if (libError) {
130→        console.error('supabase error fetching library:', libError.message);
131→        throw { status: 500, error: 'failed to fetch library' };
132→    }
133→
134→    if (!libraryEntries || libraryEntries.length === 0) {
135→        return { data: [], hasMore: false };
136→    }
137→
138→    const hasMore = libraryEntries.length > parsedLimit;
139→    const slicedEntries = hasMore ? libraryEntries.slice(0, parsedLimit) : libraryEntries;
140→    const storyIds = slicedEntries.map(e => e.story_id);
141→
142→    // Build added_at map for cursor
143→    const addedAtMap = {};
144→    slicedEntries.forEach(e => { addedAtMap[e.story_id] = e.added_at; });
145→
146→    // Batch-fetch stories
147→    const { data: stories, error: storyError } = await supabase
148→        .from('stories')
149→        .select('*')
150→        .in('id', storyIds);
151→
152→    if (storyError) {
153→        console.error('supabase error fetching library stories:', storyError.message);
154→        throw { status: 500, error: 'failed to fetch library stories' };
155→    }
156→
157→    if (!stories || stories.length === 0) {
158→        return { data: [], hasMore };
159→    }
160→
161→    // Batch-fetch author profiles
162→    const authorIds = [...new Set(stories.map(s => s.author_id))];
163→    const { data: authors } = await supabase
164→        .from('users')
165→        .select('id, name, image_url, username, badge')
166→        .in('id', authorIds);
167→
168→    const authorMap = {};
169→    (authors || []).forEach(a => { authorMap[a.id] = a; });
170→
171→    // Build story map for ordering
172→    const storyMap = {};
173→    stories.forEach(s => {
174→        const { embedding, ...rest } = s;
175→        storyMap[s.id] = { ...rest, users: authorMap[s.author_id] || null, in_library: true, added_at: addedAtMap[s.id] };
176→    });
177→
178→    // Return in library order (most recently added first)
179→    const ordered = storyIds.map(id => storyMap[id]).filter(Boolean);
180→
181→    return { data: ordered, hasMore };
182→};
