184→// ── Comments ──
185→export const getCommentsService = async (chapterId, paragraphIndex) => {
186→    if (!chapterId) {
187→        throw { status: 400, error: 'chapterId is required' };
188→    }
189→
190→    let query = supabase
191→        .from('story_comments')
192→        .select(`*, users(id, name, image_url, username, badge)`)
193→        .eq('chapter_id', chapterId)
194→        .is('parent_id', null)
195→        .order('created_at', { ascending: true });
196→
197→    if (paragraphIndex !== undefined && paragraphIndex !== null) {
198→        query = query.eq('paragraph_index', parseInt(paragraphIndex));
199→    }
200→
201→    const { data: comments, error } = await query;
202→
203→    if (error) {
204→        console.error('supabase error fetching comments:', error.message);
205→        throw { status: 500, error: 'failed to fetch comments' };
206→    }
207→
208→    // Fetch replies for all top-level comments
209→    if (comments && comments.length > 0) {
210→        const commentIds = comments.map(c => c.id);
211→        const { data: replies, error: replyError } = await supabase
212→            .from('story_comments')
213→            .select(`*, users(id, name, image_url, username, badge)`)
214→            .in('parent_id', commentIds)
215→            .order('created_at', { ascending: true });
216→
217→        if (!replyError && replies) {
218→            const replyMap = {};
219→            replies.forEach(r => {
220→                if (!replyMap[r.parent_id]) replyMap[r.parent_id] = [];
221→                replyMap[r.parent_id].push(r);
222→            });
223→            comments.forEach(c => {
224→                c.replies = replyMap[c.id] || [];
225→            });
226→        }
227→    }
228→
229→    return comments || [];
230→};
