 34→export const createStoryService = async (userId, title, description, status, privacy, tags, coverFile) => {
 35→    if (!userId) {
 36→        throw { status: 400, error: 'userId is undefined' };
 37→    }
 38→    if (!title || typeof title !== 'string' || title.trim().length === 0) {
 39→        throw { status: 400, error: 'title is required' };
 40→    }
 41→    if (title.length > 200) {
 42→        throw { status: 400, error: 'title must be 200 characters or less' };
 43→    }
 44→    if (description && description.length > 2000) {
 45→        throw { status: 400, error: 'description must be 2000 characters or less' };
 46→    }
 47→
 48→    const validStatuses = ['ongoing', 'completed', 'hiatus'];
 49→    const validPrivacy = ['public', 'private'];
 50→    const storyStatus = validStatuses.includes(status) ? status : 'ongoing';
 51→    const storyPrivacy = validPrivacy.includes(privacy) ? privacy : 'public';
 52→
 53→    let parsedTags = [];
 54→    if (tags) {
 55→        try {
 56→            parsedTags = typeof tags === 'string' ? JSON.parse(tags) : tags;
 57→            if (!Array.isArray(parsedTags)) parsedTags = [];
 58→            parsedTags = parsedTags.slice(0, 10).map(t => String(t).trim()).filter(Boolean);
 59→        } catch {
 60→            parsedTags = [];
 61→        }
 62→    }
 63→
 64→    let coverUrl = null;
 65→    if (coverFile) {
 66→        coverUrl = await imageUploader(coverFile, userId, 'story-covers');
 67→    }
 68→
 69→    const embedding = await GenerateEmbeddings(title.trim(), (description || '').trim());
 70→    if (!embedding || !Array.isArray(embedding) || embedding.length === 0) {
 71→        throw { status: 400, error: 'failed to generate story embedding' };
 72→    }
 73→
 74→    const { data, error } = await supabase
 75→        .from('stories')
 76→        .insert({
 77→            author_id: userId,
 78→            title: title.trim(),
 79→            description: (description || '').trim(),
 80→            cover_url: coverUrl,
 81→            status: storyStatus,
 82→            privacy: storyPrivacy,
 83→            tags: parsedTags,
 84→            embedding,
 85→        })
 86→        .select('*')
 87→        .single();
 88→
 89→    if (error) {
 90→        console.error('supabase error creating story:', error.message);
 91→        throw { status: 500, error: 'failed to create story' };
 92→    }
 93→
 94→    return stripEmbedding(data);
 95→};
 96→
 97→export const getStoriesService = async (limit, before, status, tag, userId) => {
 98→    const parsedLimit = Math.min(Math.max(parseInt(limit) || 10, 1), 20);
 99→
100→    let query = supabase
101→        .from('stories')
102→        .select('*')
103→        .eq('privacy', 'public')
104→        .order('created_at', { ascending: false })
105→        .limit(parsedLimit + 1);
106→
107→    if (before) {
108→        query = query.lt('created_at', before);
109→    }
110→    if (status && ['ongoing', 'completed', 'hiatus'].includes(status)) {
111→        query = query.eq('status', status);
112→    }
113→    if (tag) {
114→        query = query.contains('tags', [tag]);
115→    }
116→
117→    const { data, error } = await query;
118→
119→    if (error) {
120→        console.error('supabase error fetching stories:', error.message);
121→        throw { status: 500, error: 'failed to fetch stories' };
122→    }
123→
124→    if (!data || data.length === 0) {
125→        return { data: [], hasMore: false };
126→    }
127→
128→    // Batch-fetch author profiles
129→    const authorMap = await fetchAuthorProfiles(data.map(s => s.author_id));
130→
131→    // Fetch user interaction flags if logged in
132→    let userVotedSet = new Set();
133→    let userLibrarySet = new Set();
134→
135→    if (userId) {
136→        const storyIds = data.map(s => s.id);
137→        const [votes, library] = await Promise.all([
138→            supabase.from('story_votes').select('story_id').in('story_id', storyIds).eq('user_id', userId),
139→            supabase.from('story_library').select('story_id').in('story_id', storyIds).eq('user_id', userId),
140→        ]);
141→
142→        if (votes.data) userVotedSet = new Set(votes.data.map(v => v.story_id));
143→        if (library.data) userLibrarySet = new Set(library.data.map(l => l.story_id));
144→    }
145→
146→    const formatted = data.map(story => ({
147→        ...stripEmbedding(story),
148→        users: authorMap[story.author_id] || null,
149→        has_voted: userVotedSet.has(story.id),
150→        in_library: userLibrarySet.has(story.id),
151→    }));
152→
153→    const hasMore = data.length > parsedLimit;
154→    const sliced = hasMore ? formatted.slice(0, parsedLimit) : formatted;
155→
156→    return { data: sliced, hasMore };
157→};
158→
159→export const getStoryByIdService = async (storyId, userId) => {
160→    if (!storyId) {
161→        throw { status: 400, error: 'storyId is required' };
162→    }
163→
164→    const { data: story, error } = await supabase
165→        .from('stories')
166→        .select('*')
167→        .eq('id', storyId)
168→        .single();
169→
170→    if (error || !story) {
171→        console.error('supabase error fetching story:', error?.message);
172→        throw { status: 404, error: 'story not found' };
173→    }
174→
175→    // Non-author can't see private stories
176→    if (story.privacy === 'private' && story.author_id !== userId) {
177→        throw { status: 404, error: 'story not found' };
178→    }
179→
180→    // Fetch author profile + chapters in parallel
181→    const [authorMap, chapResult] = await Promise.all([
182→        fetchAuthorProfiles([story.author_id]),
183→        supabase
184→            .from('chapters')
185→            .select('id, chapter_number, title, word_count, status, published_at, created_at')
186→            .eq('story_id', storyId)
187→            .order('chapter_number', { ascending: true }),
188→    ]);
189→
190→    if (chapResult.error) {
191→        console.error('supabase error fetching chapters:', chapResult.error.message);
192→    }
193→
194→    // Filter chapters for non-authors
195→    const isAuthor = story.author_id === userId;
196→    const chapters = chapResult.data || [];
197→    const visibleChapters = isAuthor
198→        ? chapters
199→        : chapters.filter(c => c.status === 'published');
200→
201→    // Fetch user flags
202→    let hasVoted = false;
203→    let inLibrary = false;
204→    let readingProgress = null;
205→
206→    if (userId) {
207→        const [voteRes, libRes, progressRes] = await Promise.all([
208→            supabase.from('story_votes').select('id').eq('story_id', storyId).eq('user_id', userId).maybeSingle(),
