234→export const reorderChaptersService = async (storyId, userId, chapterOrder) => {
235→    if (!storyId || !userId) {
236→        throw { status: 400, error: 'storyId and userId are required' };
237→    }
238→    if (!Array.isArray(chapterOrder) || chapterOrder.length === 0) {
239→        throw { status: 400, error: 'chapterOrder must be a non-empty array of chapter ids' };
240→    }
241→
242→    await verifyStoryOwnership(storyId, userId);
